typedef struct latLong
{
  float lat;
  float lng;
} LatLong;

__kernel void euclid(__global LatLong *d_locations, __global float *d_distances, int numRecords, float lat, float lng)
{
    size_t globalId = get_global_id(0) + get_global_size(0) * get_global_id(1);
    if (globalId < numRecords) {
        LatLong latLong = d_locations[globalId];
        d_distances[globalId] = sqrt((lat - latLong.lat)*(lat - latLong.lat) + (lng - latLong.lng)*(lng - latLong.lng));
    }
}
